#!/usr/bin/env python3
"""Patch scripts/replay.js to allow replaying matches no longer in the snapshot."""
import base64, os, sys, shutil
DATA = ""
def main():
    if not os.path.isdir("scripts"):
        print("ERROR: run from the kaching-tell repo root."); sys.exit(1)
    path = "scripts/replay.js"
    if os.path.exists(path):
        shutil.copy2(path, path + ".bak2")
    with open(path, "wb") as fh:
        fh.write(base64.b64decode(DATA))
    print("wrote", path, "(backed up .bak2)")
    print("")
    print("Now run:")
    print('  node scripts/replay.js 18257865 2026-07-18T21:00:14Z France England')
if __name__ == "__main__":
    main()
